                code: `import hashlib
from datetime import datetime, timedelta

class SimpleCache:
    def __init__(self, ttl_minutes=30):
        self.cache = {}
        self.ttl = timedelta(minutes=ttl_minutes)

    def _key(self, prompt, config):
        """Generate cache key"""
        content = f"{prompt}::{config}"
        return hashlib.md5(content.encode()).hexdigest()

    def get(self, prompt, config):
        """Get cached response"""
        key = self._key(prompt, config)

        if key in self.cache:
            entry = self.cache[key]
            if datetime.now() - entry['time'] < self.ttl:
                return entry['response']
            else:
                del self.cache[key]  # Expired

        return None

    def set(self, prompt, config, response):
        """Cache a response"""
        key = self._key(prompt, config)
        self.cache[key] = {
            'response': response,
            'time': datetime.now()
        }

# Usage
cache = SimpleCache(ttl_minutes=30)

prompt = "Analyze for security issues"
config = "interface Gi0/1\\n ip address 10.1.1.1 255.255.255.0"

# First call - miss
result = cache.get(prompt, config)
print(f"First call: {'HIT' if result else 'MISS'}")

# Cache the response
cache.set(prompt, config, "No critical issues")

# Second call - hit
result = cache.get(prompt, config)
print(f"Second call: {'HIT' if result else 'MISS'}")
print(f"Result: {result}")`
