ENTITY_SCHEMA = {
    "Device": ["hostname", "ip", "type", "location", "criticality"],
    "Vulnerability": ["cve_id", "cvss_score", "description", "patch_status"],
    "Alert": ["alert_id", "severity", "timestamp", "status"],
    "User": ["username", "department", "access_level"],
    "Subnet": ["cidr", "vlan", "zone"]
}

RELATIONSHIP_TYPES = [
    ("Device", "CONNECTS_TO", "Device"),
    ("Device", "HAS_VULNERABILITY", "Vulnerability"),
    ("Alert", "TRIGGERED_BY", "Device"),
    ("User", "ACCESSES", "Device"),
    ("Device", "BELONGS_TO", "Subnet")
]
